from datetime import datetime

events = [
    {
        "id": "evt_jVMIDhEDqjvd8kCJXN",
        "created_at": "2026-06-11T08:54:48.391Z",
        "successful_at": "2026-06-11T08:54:53.650Z"
    },
    {
        "id": "evt_ngJKSsKmzrAbAYNRcT",
        "created_at": "2026-06-11T08:54:47.272Z",
        "successful_at": "2026-06-11T08:54:52.336Z"
    },
    {
        "id": "evt_in9SmLr85kQgxdCkIh",
        "created_at": "2026-06-11T08:54:46.134Z",
        "successful_at": "2026-06-11T08:54:51.283Z"
    }
]

print("=== Delay Verification ===")
for e in events:
    created = datetime.fromisoformat(e['created_at'].replace('Z', '+00:00'))
    delivered = datetime.fromisoformat(e['successful_at'].replace('Z', '+00:00'))
    delay_ms = (delivered - created).total_seconds() * 1000
    status = "✓ PASS" if 5000 <= delay_ms < 10000 else "✗ FAIL"
    print(f"Event {e['id']}: delay={delay_ms:.0f}ms {status}")

print("\n=== Event IDs for log file ===")
for e in events:
    print(f"Event ID: {e['id']}")
EOF
